import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface Animal {
  id: number;
  identificador_unico: string;
  nombre: string;
  sexo: string;
  categoria: string;
  estado: string;
  raza_nombre: string;
  ubicacion_nombre: string;
  fecha_nacimiento: string;
}

const Animals: React.FC = () => {
  const [animals, setAnimals] = useState<Animal[]>([]);
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({
    identificador_unico: '',
    nombre: '',
    sexo: 'hembra',
    categoria: 'lechon',
    fecha_nacimiento: '',
    peso_nacimiento: '',
    observaciones: ''
  });

  useEffect(() => {
    loadAnimals();
  }, []);

  const loadAnimals = async () => {
    try {
      const response = await api.get('/animals');
      setAnimals(response.data);
    } catch (error) {
      console.error('Error cargando animales:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/animals', formData);
      alert('Animal registrado exitosamente');
      setFormData({
        identificador_unico: '',
        nombre: '',
        sexo: 'hembra',
        categoria: 'lechon',
        fecha_nacimiento: '',
        peso_nacimiento: '',
        observaciones: ''
      });
      setShowForm(false);
      loadAnimals();
    } catch (error) {
      console.error('Error guardando animal:', error);
      alert('Error guardando animal');
    }
  };

  if (loading) return (
    <div className="page-inner">
      <div className="card">
        <div style={{ padding: '40px', textAlign: 'center' }}>
          <i className="fas fa-spinner fa-spin" style={{ fontSize: '24px', color: '#1572e8' }}></i>
          <p style={{ marginTop: '10px', color: '#6c757d' }}>Cargando animales...</p>
        </div>
      </div>
    </div>
  );

  return (
    <div className="page-inner">
      <div className="card">
        <div className="card-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 className="card-title">
              <i className="fas fa-paw" style={{ marginRight: '10px' }}></i>
              Gestión de Animales ({animals.length})
            </h4>
            <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
              <i className={`fas ${showForm ? 'fa-times' : 'fa-plus'}`} style={{ marginRight: '8px' }}></i>
              {showForm ? 'Cancelar' : 'Nuevo Animal'}
            </button>
          </div>
        </div>

        <div style={{ padding: '25px' }}>
          {/* Formulario */}
          {showForm && (
            <div className="card" style={{ marginBottom: '25px' }}>
              <div className="card-header">
                <h5 className="card-title">
                  <i className="fas fa-plus" style={{ marginRight: '8px' }}></i>
                  Nuevo Animal
                </h5>
              </div>
              <div style={{ padding: '20px' }}>
                <form onSubmit={handleSubmit}>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '15px', marginBottom: '15px' }}>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>ID Único *</label>
                      <input
                        type="text"
                        value={formData.identificador_unico}
                        onChange={(e) => setFormData({...formData, identificador_unico: e.target.value})}
                        required
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                        placeholder="Ej: CER001"
                      />
                    </div>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Nombre</label>
                      <input
                        type="text"
                        value={formData.nombre}
                        onChange={(e) => setFormData({...formData, nombre: e.target.value})}
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                        placeholder="Nombre del animal"
                      />
                    </div>
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '15px', marginBottom: '15px' }}>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Sexo</label>
                      <select
                        value={formData.sexo}
                        onChange={(e) => setFormData({...formData, sexo: e.target.value})}
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                      >
                        <option value="hembra">Hembra</option>
                        <option value="macho">Macho</option>
                      </select>
                    </div>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Categoría</label>
                      <select
                        value={formData.categoria}
                        onChange={(e) => setFormData({...formData, categoria: e.target.value})}
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                      >
                        <option value="lechon">Lechón</option>
                        <option value="recria">Recría</option>
                        <option value="desarrollo">Desarrollo</option>
                        <option value="engorde">Engorde</option>
                        <option value="reproductor">Reproductor</option>
                      </select>
                    </div>
                  </div>

                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '15px', marginBottom: '15px' }}>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Fecha Nacimiento</label>
                      <input
                        type="date"
                        value={formData.fecha_nacimiento}
                        onChange={(e) => setFormData({...formData, fecha_nacimiento: e.target.value})}
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                      />
                    </div>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Peso Nacimiento (kg)</label>
                      <input
                        type="number"
                        step="0.1"
                        value={formData.peso_nacimiento}
                        onChange={(e) => setFormData({...formData, peso_nacimiento: e.target.value})}
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                        placeholder="1.5"
                      />
                    </div>
                  </div>

                  <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Observaciones</label>
                    <textarea
                      value={formData.observaciones}
                      onChange={(e) => setFormData({...formData, observaciones: e.target.value})}
                      rows={3}
                      style={{
                        width: '100%',
                        padding: '10px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px',
                        resize: 'vertical'
                      }}
                      placeholder="Notas adicionales..."
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '10px' }}>
                    <button type="submit" className="btn btn-success">
                      <i className="fas fa-save" style={{ marginRight: '8px' }}></i>
                      Guardar
                    </button>
                    <button type="button" className="btn btn-secondary" onClick={() => setShowForm(false)}>
                      Cancelar
                    </button>
                  </div>
                </form>
              </div>
            </div>
          )}

          {/* Stats */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '25px' }}>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#1572e8' }}>{animals.length}</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>TOTAL ANIMALES</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#31ce36' }}>
                {animals.filter(a => a.estado === 'activo').length}
              </div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>ACTIVOS</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#ffad46' }}>
                {animals.filter(a => a.categoria === 'reproductor').length}
              </div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>REPRODUCTORES</div>
            </div>
          </div>

          {/* Table */}
          <div className="table-responsive">
            <table className="table">
              <thead>
                <tr>
                  <th>ID</th>
                  <th>Nombre</th>
                  <th>Sexo</th>
                  <th>Categoría</th>
                  <th>Estado</th>
                  <th>Raza</th>
                  <th>Ubicación</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {animals.map(animal => (
                  <tr key={animal.id}>
                    <td style={{ fontWeight: '600' }}>{animal.identificador_unico}</td>
                    <td>{animal.nombre || '-'}</td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: animal.sexo === 'hembra' ? '#f25961' : '#1572e8',
                        color: '#ffffff'
                      }}>
                        {animal.sexo === 'hembra' ? 'Hembra' : 'Macho'}
                      </span>
                    </td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: '#6c757d',
                        color: '#ffffff',
                        textTransform: 'capitalize'
                      }}>
                        {animal.categoria}
                      </span>
                    </td>
                    <td>
                      <span style={{
                        padding: '4px 8px',
                        borderRadius: '12px',
                        fontSize: '12px',
                        fontWeight: '600',
                        background: animal.estado === 'activo' ? '#31ce36' : 
                                   animal.estado === 'vendido' ? '#ffad46' : '#f25961',
                        color: '#ffffff',
                        textTransform: 'capitalize'
                      }}>
                        {animal.estado}
                      </span>
                    </td>
                    <td>{animal.raza_nombre || '-'}</td>
                    <td>{animal.ubicacion_nombre || '-'}</td>
                    <td>
                      <div style={{ display: 'flex', gap: '5px' }}>
                        <button className="btn btn-primary btn-sm" title="Ver">
                          <i className="fas fa-eye"></i>
                        </button>
                        <button className="btn btn-warning btn-sm" title="Editar">
                          <i className="fas fa-edit"></i>
                        </button>
                        <button className="btn btn-danger btn-sm" title="Eliminar">
                          <i className="fas fa-trash"></i>
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {animals.length === 0 && (
            <div style={{ textAlign: 'center', padding: '40px', color: '#6c757d' }}>
              <i className="fas fa-paw" style={{ fontSize: '48px', marginBottom: '15px', opacity: 0.5 }}></i>
              <h5>No hay animales registrados</h5>
              <p>Comienza registrando tu primer animal</p>
              <button className="btn btn-primary" onClick={() => setShowForm(true)}>
                <i className="fas fa-plus" style={{ marginRight: '8px' }}></i>
                Registrar Animal
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Animals;
